import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import Home from './pages/Home';
import Menu from './pages/Menu';
import Cart from './pages/Cart';
import OrderHistory from './pages/OrderHistory';
import Dashboard from './pages/Dashboard';
import './App.css';

function App() {
  const [cart, setCart] = useState([]);
  const [user, setUser] = useState(null);

  useEffect(() => {
    // For demo purposes, we'll pick the first user from the DB
    // In a real app, this would be handled by authentication
    const fetchUser = async () => {
      try {
        const response = await fetch('http://localhost:3000/users');
        const data = await response.json();
        if (data.length > 0) setUser(data[0]);
      } catch (error) {
        console.error("Error fetching user:", error);
      }
    };
    fetchUser();
  }, []);

  const addToCart = (item, restaurantId) => {
    if (cart.length > 0 && cart[0].restaurantId !== restaurantId) {
      if (window.confirm("Adding items from a different restaurant will clear your current cart. Continue?")) {
        setCart([{ ...item, quantity: 1, restaurantId }]);
      }
    } else {
      const existingItem = cart.find(i => i._id === item._id);
      if (existingItem) {
        setCart(cart.map(i => i._id === item._id ? { ...i, quantity: i.quantity + 1 } : i));
      } else {
        setCart([...cart, { ...item, quantity: 1, restaurantId }]);
      }
    }
  };

  const removeFromCart = (itemId) => {
    setCart(cart.filter(i => i._id !== itemId));
  };

  const clearCart = () => setCart([]);

  return (
    <Router>
      <div className="App">
        <nav className="navbar">
          <Link to="/" className="nav-logo">HERMES FOODS</Link>
          <div className="nav-links">
            <Link to="/">Restaurants</Link>
            <Link to="/orders">My Orders</Link>
            <Link to="/cart">Cart ({cart.reduce((acc, item) => acc + item.quantity, 0)})</Link>
            <Link to="/dashboard">Dashboard</Link>
          </div>
          {user && <span className="user-info">Welcome, {user.name}</span>}
        </nav>

        <main className="container">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/restaurant/:id" element={<Menu addToCart={addToCart} />} />
            <Route path="/cart" element={<Cart cart={cart} user={user} removeFromCart={removeFromCart} clearCart={clearCart} />} />
            <Route path="/orders" element={<OrderHistory user={user} />} />
            <Route path="/dashboard" element={<Dashboard />} />
          </Routes>
        </main>
      </div>
    </Router>
  );
}

export default App;
